#!/bin/bash
# 00b_build_negatives_onpolicy.sh — Stage-2-prep: ON-POLICY axis-ablated
# rejected responses, generated by the SFT warm-start checkpoint.
#
# Why on-policy:
#   Tulu-3 (arXiv:2411.15124) and "What Matters in DPO Data" (arXiv:2508.18312)
#   both find that DPO works best when the rejected traces are sampled from
#   the SFT model itself — not the base model.  Our previous negatives_qwen3vl8b/
#   were generated by base Qwen3-VL, so the resulting DPO has been training
#   off-policy.  This script regenerates the negatives from the SFT ckpt.
#
# Usage:
#   SFT_CKPT=/path/to/sof_sft_warmstart_xxx \
#     bash scripts/00b_build_negatives_onpolicy.sh
#
#   # Debug (per-axis row cap):
#   MAX_ROWS=20 SFT_CKPT=... bash scripts/00b_build_negatives_onpolicy.sh
#
#   # Smaller frame budget (for fast smoke test):
#   N_FRAMES_FULL=64 N_FRAMES_AUDIO=64 SFT_CKPT=... bash scripts/00b_build_negatives_onpolicy.sh
set -euo pipefail

REPO="$(cd "$(dirname "$0")/.." && pwd)"

SFT_CKPT="${SFT_CKPT:?SFT_CKPT env var is required (path to PEFT adapter dir)}"
[[ -d "$SFT_CKPT" ]] || { echo "❌ SFT_CKPT not found: $SFT_CKPT"; exit 1; }
[[ -f "$SFT_CKPT/adapter_config.json" ]] || \
  { echo "❌ no adapter_config.json under SFT_CKPT — not a PEFT dir"; exit 1; }

# Tag the output dir by the SFT run name so multiple SFT variants can coexist.
SFT_TAG="$(basename "$SFT_CKPT")"
NUM_SHARDS="${NUM_SHARDS:-8}"
OUT_DIR="${OUT_DIR:-$REPO/data/negatives_onpolicy_${SFT_TAG}}"
MAX_ROWS="${MAX_ROWS:--1}"
# Match the SFT visual distribution by default.  These are inference-only
# (no backward), so we can run heavier per-frame budgets than training.
N_FRAMES_FULL="${N_FRAMES_FULL:-256}"
N_FRAMES_CLIP="${N_FRAMES_CLIP:-96}"
N_FRAMES_AUDIO="${N_FRAMES_AUDIO:-256}"
MAX_NEW_TOKENS="${MAX_NEW_TOKENS:-384}"
MODEL_ID="${MODEL_ID:-Qwen/Qwen3-VL-8B-Instruct}"

LOG_DIR="$REPO/logs/00b_build_negatives_onpolicy/${SFT_TAG}"
mkdir -p "$OUT_DIR" "$LOG_DIR"

# Hard-verify the decord guard is importable BEFORE shards launch.
python -c "import sys; sys.path.insert(0, '$REPO/scripts'); import decord_only_guard" \
  || { echo "❌ decord_only_guard NOT importable — aborting before pod-killer fires"; exit 1; }
echo "✅ decord_only_guard preflight OK"

cat <<EOF
════════════════════════════════════════════════════════════════════
  ON-POLICY NEGATIVE GENERATION  (sof_dpo_generate_negatives.py)
  GPUs/shards:  $NUM_SHARDS
  Base model:   $MODEL_ID
  SFT adapter:  $SFT_CKPT
  Out dir:      $OUT_DIR
  Logs:         $LOG_DIR/shard*.log
  Frames:       full=$N_FRAMES_FULL  clip=$N_FRAMES_CLIP  audio=$N_FRAMES_AUDIO
  max_rows:     $MAX_ROWS  (debug cap; -1 = full set)
EOF
echo "════════════════════════════════════════════════════════════════════"

PIDS=()
for SHARD in $(seq 0 $((NUM_SHARDS - 1))); do
    LOG="$LOG_DIR/shard${SHARD}.log"
    echo "  launch shard $SHARD on GPU $SHARD  -> $LOG"
    CUDA_VISIBLE_DEVICES=$SHARD \
    NUM_SHARDS=$NUM_SHARDS SHARD_ID=$SHARD \
    python3 "$REPO/build_pairs/sof_dpo_generate_negatives.py" \
        --model-id "$MODEL_ID" \
        --sft-adapter-path "$SFT_CKPT" \
        --out-dir "$OUT_DIR" \
        --max-rows "$MAX_ROWS" \
        --n-frames-full "$N_FRAMES_FULL" \
        --n-frames-clip "$N_FRAMES_CLIP" \
        --n-frames-audio "$N_FRAMES_AUDIO" \
        --max-new-tokens "$MAX_NEW_TOKENS" \
        > "$LOG" 2>&1 &
    PIDS+=($!)
done

echo "[00b] waiting for ${#PIDS[@]} shards ..."
FAIL=0
for p in "${PIDS[@]}"; do
    if ! wait "$p"; then FAIL=$((FAIL+1)); fi
done
echo "[00b] done. failed shards: $FAIL"

# Per-axis row counts
echo "[00b] per-axis row counts:"
for ax in visual audio time priority; do
    n=$(cat "$OUT_DIR"/negatives_${ax}.shard*.jsonl 2>/dev/null | wc -l || echo 0)
    echo "    $ax  $n"
done
echo "[00b] OUT_DIR=$OUT_DIR"
